Your code has a critical **race condition vulnerability** that allows attackers to drain accounts by exploiting the time gap between checking and updating the balance. This is known as a Time-of-Check to Time-of-Use (TOCTOU) attack.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// In-memory wallet balances (simulating database)
const wallets = {
  'user123': { balance: 1000 },
  'user456': { balance: 500 }
};

app.post('/api/transfer', async (req, res) => {
  const { fromUserId, toUserId, amount } = req.body;

  // VULNERABLE: Check balance (Time-of-Check)
  const senderWallet = wallets[fromUserId];

  if (!senderWallet) {
    return res.status(404).json({ error: 'Sender wallet not found' });
  }

  if (senderWallet.balance < amount) {
    return res.status(400).json({ error: 'Insufficient funds' });
  }

  // Simulate processing delay (network, external API, etc.)
  await processPayment(fromUserId, toUserId, amount);

  // VULNERABLE: Update balance (Time-of-Use)
  // Race window: balance could have changed!
  wallets[fromUserId].balance -= amount;
  wallets[toUserId].balance += amount;

  res.json({ success: true, newBalance: wallets[fromUserId].balance });
});

async function processPayment(from, to, amount) {
  // Simulates external payment processing delay
  return new Promise(resolve => setTimeout(resolve, 100));
}

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker sends 10 concurrent requests to transfer $900 each
# when account only has $1000 balance
for i in {1..10}; do
  curl -X POST http://localhost:3000/api/transfer \
    -H "Content-Type: application/json" \
    -d '{"fromUserId":"user123","toUserId":"attacker","amount":900}' &
done
wait
# Result: All 10 requests pass the balance check simultaneously
# Account is drained of $9000 despite only having $1000
```

**Why This Is Dangerous**:
- **TOCTOU Gap**: The balance check and deduction are not atomic; concurrent requests can all pass the check before any deduction occurs
- **No Locking Mechanism**: Multiple requests can read the same balance simultaneously
- **Negative Balance**: Account can go negative, causing financial losses for the platform
- **Non-Deterministic**: Bug is hard to reproduce in testing but exploitable in production

**SECURE VERSION**:

```javascript
const express = require('express');
const { Mutex } = require('async-mutex');
const app = express();

// Per-user mutexes for fine-grained locking
const walletLocks = new Map();

const wallets = {
  'user123': { balance: 1000, version: 0 },
  'user456': { balance: 500, version: 0 }
};

function getWalletLock(userId) {
  if (!walletLocks.has(userId)) {
    walletLocks.set(userId, new Mutex());
  }
  return walletLocks.get(userId);
}

app.post('/api/transfer', async (req, res) => {
  const { fromUserId, toUserId, amount } = req.body;

  // Input validation
  if (!fromUserId || !toUserId || typeof amount !== 'number' || amount <= 0) {
    return res.status(400).json({ error: 'Invalid transfer parameters' });
  }

  // SECURE: Acquire lock on sender's wallet before any operations
  const senderLock = getWalletLock(fromUserId);

  const release = await senderLock.acquire();

  try {
    const senderWallet = wallets[fromUserId];
    const receiverWallet = wallets[toUserId];

    if (!senderWallet || !receiverWallet) {
      return res.status(404).json({ error: 'Wallet not found' });
    }

    // SECURE: Check balance while holding lock
    if (senderWallet.balance < amount) {
      return res.status(400).json({ error: 'Insufficient funds' });
    }

    // SECURE: Atomic update while lock is held
    senderWallet.balance -= amount;
    senderWallet.version += 1;
    receiverWallet.balance += amount;
    receiverWallet.version += 1;

    // Process after state is consistent
    await processPayment(fromUserId, toUserId, amount);

    res.json({ 
      success: true, 
      newBalance: senderWallet.balance,
      transactionVersion: senderWallet.version
    });
  } finally {
    // CRITICAL: Always release lock
    release();
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Mutex Locking**: Ensures only one transfer per user can execute at a time, preventing concurrent balance checks
- **Lock Acquisition Before Check**: Balance is checked only after acquiring exclusive access
- **Optimistic Concurrency Control**: Version field enables detection of concurrent modifications
- **Finally Block Release**: Lock is always released, even if errors occur, preventing deadlocks

Excellent question! In production with PostgreSQL, you need database-level controls because application-level mutexes don't work across multiple server instances. Here's a comprehensive production pattern using database transactions, row-level locking, and optimistic concurrency.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const { v4: uuidv4 } = require('uuid');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Production database pool configuration
const pool = new Pool({
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Rate limiting per user
const transferLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 10, // 10 transfers per minute
  keyGenerator: (req) => req.body.fromUserId || req.ip,
  message: { error: 'Too many transfer requests' }
});

// Idempotency tracking to prevent duplicate processing
const processedRequests = new Map();

app.post('/api/transfer', transferLimiter, async (req, res) => {
  const { fromUserId, toUserId, amount, idempotencyKey } = req.body;
  const transactionId = uuidv4();
  const startTime = Date.now();

  // Input validation
  if (!fromUserId || !toUserId || typeof amount !== 'number' || amount <= 0) {
    return res.status(400).json({ error: 'Invalid parameters' });
  }

  // Idempotency check - prevent duplicate transactions
  if (idempotencyKey && processedRequests.has(idempotencyKey)) {
    console.log(`[IDEMPOTENT] Duplicate request: ${idempotencyKey}`);
    return res.json(processedRequests.get(idempotencyKey));
  }

  const client = await pool.connect();

  try {
    // SECURE: Begin serializable transaction
    await client.query('BEGIN ISOLATION LEVEL SERIALIZABLE');

    // SECURE: SELECT FOR UPDATE - acquires row-level exclusive lock
    // This prevents other transactions from reading or modifying the row
    const senderResult = await client.query(
      `SELECT id, balance, version 
       FROM wallets 
       WHERE user_id = $1 
       FOR UPDATE NOWAIT`,  // NOWAIT fails immediately if locked
      [fromUserId]
    );

    if (senderResult.rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Sender wallet not found' });
    }

    const sender = senderResult.rows[0];

    // SECURE: Balance check with lock held
    if (parseFloat(sender.balance) < amount) {
      await client.query('ROLLBACK');
      console.warn(`[INSUFFICIENT_FUNDS] User: ${fromUserId}, Balance: ${sender.balance}, Requested: ${amount}`);
      return res.status(400).json({ error: 'Insufficient funds' });
    }

    // Lock receiver wallet
    const receiverResult = await client.query(
      `SELECT id, balance, version 
       FROM wallets 
       WHERE user_id = $1 
       FOR UPDATE`,
      [toUserId]
    );

    if (receiverResult.rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Receiver wallet not found' });
    }

    // SECURE: Atomic update with optimistic concurrency check
    const updateSender = await client.query(
      `UPDATE wallets 
       SET balance = balance - $1, 
           version = version + 1, 
           updated_at = NOW() 
       WHERE user_id = $2 AND version = $3
       RETURNING balance, version`,
      [amount, fromUserId, sender.version]
    );

    // Version mismatch = concurrent modification detected
    if (updateSender.rowCount === 0) {
      await client.query('ROLLBACK');
      console.error(`[RACE_DETECTED] Concurrent modification on wallet: ${fromUserId}`);
      return res.status(409).json({ error: 'Transaction conflict, please retry' });
    }

    await client.query(
      `UPDATE wallets 
       SET balance = balance + $1, 
           version = version + 1, 
           updated_at = NOW() 
       WHERE user_id = $2`,
      [amount, toUserId]
    );

    // Record transaction for audit trail
    await client.query(
      `INSERT INTO transactions 
       (id, from_user_id, to_user_id, amount, status, created_at, idempotency_key) 
       VALUES ($1, $2, $3, $4, 'completed', NOW(), $5)`,
      [transactionId, fromUserId, toUserId, amount, idempotencyKey]
    );

    // SECURE: Commit transaction atomically
    await client.query('COMMIT');

    const response = {
      success: true,
      transactionId,
      newBalance: updateSender.rows[0].balance,
      version: updateSender.rows[0].version
    };

    // Cache for idempotency
    if (idempotencyKey) {
      processedRequests.set(idempotencyKey, response);
      setTimeout(() => processedRequests.delete(idempotencyKey), 24 * 60 * 60 * 1000);
    }

    // Audit logging
    console.log(JSON.stringify({
      event: 'TRANSFER_SUCCESS',
      transactionId,
      fromUserId,
      toUserId,
      amount,
      duration: Date.now() - startTime,
      timestamp: new Date().toISOString()
    }));

    res.json(response);

  } catch (error) {
    await client.query('ROLLBACK');

    // Handle specific PostgreSQL errors
    if (error.code === '55P03') {
      // NOWAIT lock not available
      console.warn(`[LOCK_CONTENTION] Wallet locked: ${fromUserId}`);
      return res.status(429).json({ 
        error: 'Resource busy, please retry',
        retryAfter: 1
      });
    }

    if (error.code === '40001') {
      // Serialization failure
      console.warn(`[SERIALIZATION_FAILURE] Transaction: ${transactionId}`);
      return res.status(409).json({ 
        error: 'Transaction conflict, please retry' 
      });
    }

    console.error(JSON.stringify({
      event: 'TRANSFER_ERROR',
      transactionId,
      error: error.message,
      code: error.code,
      timestamp: new Date().toISOString()
    }));

    res.status(500).json({ error: 'Transfer failed' });

  } finally {
    client.release();
  }
});

// Health check endpoint for monitoring
app.get('/health', async (req, res) => {
  try {
    await pool.query('SELECT 1');
    res.json({ status: 'healthy', connections: pool.totalCount });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Database-Level Locking (SELECT FOR UPDATE)**:
```sql
-- Acquires exclusive row lock until transaction ends
SELECT balance FROM wallets WHERE user_id = $1 FOR UPDATE NOWAIT;
-- NOWAIT: Fail immediately if row is locked by another transaction
-- Prevents queue buildup during contention
```

2. **Serializable Transaction Isolation**:
```sql
-- Highest isolation level - transactions appear to execute sequentially
BEGIN ISOLATION LEVEL SERIALIZABLE;
-- PostgreSQL will abort transactions that would cause anomalies
```

3. **Optimistic Concurrency Control (Version Column)**:
```sql
-- Update only succeeds if version hasn't changed
UPDATE wallets 
SET balance = balance - $1, version = version + 1 
WHERE user_id = $2 AND version = $3;
-- rowCount = 0 means concurrent modification detected
```

**Additional Protections**:

- **Idempotency Keys**: Clients send unique key per request; server returns cached result for duplicates, preventing double-charges on network retries
- **Rate Limiting**: Per-user limits prevent automated exploitation attempts
- **NOWAIT Locking**: Fails fast under contention instead of blocking, improving responsiveness
- **Structured Audit Logging**: Every transaction logged with timing metrics for forensic analysis
- **Connection Pooling**: Prevents connection exhaustion under load
- **Retry Guidance**: 409 responses include retry hints for clients to implement exponential backoff
- **Health Endpoint**: Enables load balancers to route around unhealthy instances

**Database Schema for Production**:

```sql
CREATE TABLE wallets (
  id SERIAL PRIMARY KEY,
  user_id VARCHAR(64) UNIQUE NOT NULL,
  balance DECIMAL(15,2) NOT NULL DEFAULT 0 CHECK (balance >= 0),
  version INTEGER NOT NULL DEFAULT 0,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_wallets_user_id ON wallets(user_id);

CREATE TABLE transactions (
  id UUID PRIMARY KEY,
  from_user_id VARCHAR(64) NOT NULL,
  to_user_id VARCHAR(64) NOT NULL,
  amount DECIMAL(15,2) NOT NULL,
  status VARCHAR(20) NOT NULL,
  idempotency_key VARCHAR(128) UNIQUE,
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_transactions_idempotency ON transactions(idempotency_key);
```

Your code likely has a critical race condition vulnerability. This is the exact flaw that cost Revolut $20 million in 2023 - attackers exploited the gap between checking the balance and deducting funds.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;
import java.math.BigDecimal;

public class WalletService {
    private static final String DB_URL = "jdbc:postgresql://localhost/walletdb";
    private static final String DB_USER = "wallet_user";
    private static final String DB_PASS = "secure_password";

    public boolean withdraw(long userId, BigDecimal amount) {
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // VULNERABLE: Check balance in one query
            String checkSql = "SELECT balance FROM wallets WHERE user_id = ?";
            PreparedStatement checkStmt = conn.prepareStatement(checkSql);
            checkStmt.setLong(1, userId);
            ResultSet rs = checkStmt.executeQuery();

            if (rs.next()) {
                BigDecimal currentBalance = rs.getBigDecimal("balance");

                // RACE CONDITION WINDOW: Balance can change between check and update!
                if (currentBalance.compareTo(amount) >= 0) {
                    // VULNERABLE: Update balance separately
                    String updateSql = "UPDATE wallets SET balance = balance - ? WHERE user_id = ?";
                    PreparedStatement updateStmt = conn.prepareStatement(updateSql);
                    updateStmt.setBigDecimal(1, amount);
                    updateStmt.setLong(2, userId);
                    updateStmt.executeUpdate();

                    processWithdrawal(userId, amount);
                    return true;
                }
            }
            return false;
        } catch (SQLException e) {
            e.printStackTrace();
            return false;
        }
    }

    private void processWithdrawal(long userId, BigDecimal amount) {
        // External transfer processing
    }
}
```

**Attack Payload**:
```bash
# Concurrent withdrawal attack - send 100 simultaneous requests
for i in {1..100}; do
  curl -X POST "https://api.example.com/wallet/withdraw" \
    -H "Authorization: Bearer $TOKEN" \
    -d '{"amount": 1000.00}' &
done
wait
# If balance is $1000, attacker may withdraw $10,000-$50,000
```

**Why This Is Dangerous**:
- **TOCTOU Vulnerability**: Time gap between SELECT (check) and UPDATE (use) allows concurrent requests to all pass the balance check
- **No Atomicity**: The check and update are separate operations without transactional protection
- **No Row Locking**: Multiple threads can read the same balance simultaneously before any deduction occurs
- **Exponential Loss**: With 100 concurrent requests, a $1000 balance could yield $100,000 in withdrawals

**SECURE VERSION**:

```java
import java.sql.*;
import java.math.BigDecimal;
import java.util.logging.Logger;

public class SecureWalletService {
    private static final Logger logger = Logger.getLogger(SecureWalletService.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/walletdb";
    private static final String DB_USER = "wallet_user";
    private static final String DB_PASS = "secure_password";

    public WithdrawalResult withdraw(long userId, BigDecimal amount) {
        Connection conn = null;
        try {
            conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
            conn.setAutoCommit(false); // Start transaction
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            // SECURE: Atomic check-and-update with row-level locking
            String atomicUpdateSql = 
                "UPDATE wallets SET balance = balance - ?, updated_at = NOW() " +
                "WHERE user_id = ? AND balance >= ? " +
                "RETURNING balance";

            PreparedStatement stmt = conn.prepareStatement(atomicUpdateSql);
            stmt.setBigDecimal(1, amount);
            stmt.setLong(2, userId);
            stmt.setBigDecimal(3, amount);

            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                BigDecimal newBalance = rs.getBigDecimal("balance");

                // Record transaction in same atomic operation
                recordTransaction(conn, userId, amount, "WITHDRAWAL");

                conn.commit();
                logger.info(String.format("Withdrawal successful: user=%d, amount=%s, newBalance=%s",
                    userId, amount, newBalance));
                return new WithdrawalResult(true, newBalance, null);
            } else {
                conn.rollback();
                logger.warning(String.format("Insufficient funds: user=%d, requested=%s", userId, amount));
                return new WithdrawalResult(false, null, "Insufficient funds");
            }

        } catch (SQLException e) {
            if (conn != null) {
                try { conn.rollback(); } catch (SQLException ex) { /* log */ }
            }
            logger.severe(String.format("Withdrawal failed: user=%d, error=%s", userId, e.getMessage()));
            return new WithdrawalResult(false, null, "Transaction failed");
        } finally {
            if (conn != null) {
                try { conn.close(); } catch (SQLException e) { /* log */ }
            }
        }
    }

    private void recordTransaction(Connection conn, long userId, BigDecimal amount, String type) 
            throws SQLException {
        String sql = "INSERT INTO transactions (user_id, amount, type, created_at) VALUES (?, ?, ?, NOW())";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        stmt.setBigDecimal(2, amount);
        stmt.setString(3, type);
        stmt.executeUpdate();
    }
}

class WithdrawalResult {
    public final boolean success;
    public final BigDecimal newBalance;
    public final String error;

    public WithdrawalResult(boolean success, BigDecimal newBalance, String error) {
        this.success = success;
        this.newBalance = newBalance;
        this.error = error;
    }
}
```

**Key Security Controls**:
- **Atomic UPDATE with WHERE clause**: The balance check and deduction happen in a single SQL statement - if balance < amount, no rows are updated
- **SERIALIZABLE isolation**: Prevents concurrent transactions from seeing uncommitted changes
- **RETURNING clause**: Gets the new balance without a separate query, eliminating race window
- **Transaction boundaries**: All related operations (balance update, transaction record) succeed or fail together

Excellent question! Multi-resource operations introduce even more complex race conditions. The 2024 Stripe incident involved exactly this pattern where transfers between accounts had a brief window for exploitation. Here's a production-ready approach using pessimistic locking and the Two-Phase Commit pattern.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.math.BigDecimal;
import java.util.UUID;
import java.util.concurrent.locks.ReentrantLock;
import java.util.logging.Logger;
import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;

public class ProductionTransferService {
    private static final Logger logger = Logger.getLogger(ProductionTransferService.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/walletdb";
    private static final String DB_USER = "wallet_user";
    private static final String DB_PASS = "secure_password";

    // Application-level lock manager for distributed scenarios
    private static final ConcurrentHashMap<Long, ReentrantLock> accountLocks = new ConcurrentHashMap<>();

    // Idempotency tracking
    private static final ConcurrentHashMap<String, TransferResult> completedTransfers = new ConcurrentHashMap<>();

    /**
     * Production-ready transfer with race condition prevention.
     * Uses: Pessimistic locking, consistent lock ordering, idempotency, audit trail
     */
    public TransferResult transfer(String idempotencyKey, long fromUserId, long toUserId, 
                                    BigDecimal amount, String description) {

        // DEFENSE 1: Idempotency check - prevents duplicate processing
        TransferResult existing = completedTransfers.get(idempotencyKey);
        if (existing != null) {
            logger.info(String.format("Duplicate transfer request: key=%s", idempotencyKey));
            return existing;
        }

        // DEFENSE 2: Input validation
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            return new TransferResult(false, null, "Invalid amount", null);
        }
        if (fromUserId == toUserId) {
            return new TransferResult(false, null, "Cannot transfer to same account", null);
        }

        // DEFENSE 3: Consistent lock ordering - CRITICAL for deadlock prevention
        // Always lock lower ID first to prevent circular waits
        long firstLock = Math.min(fromUserId, toUserId);
        long secondLock = Math.max(fromUserId, toUserId);

        ReentrantLock lock1 = accountLocks.computeIfAbsent(firstLock, k -> new ReentrantLock());
        ReentrantLock lock2 = accountLocks.computeIfAbsent(secondLock, k -> new ReentrantLock());

        lock1.lock();
        lock2.lock();

        Connection conn = null;
        String transferId = UUID.randomUUID().toString();

        try {
            conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            // DEFENSE 4: Database-level pessimistic locking with SELECT FOR UPDATE
            // Lock both rows in consistent order
            String lockSql = "SELECT user_id, balance FROM wallets WHERE user_id IN (?, ?) " +
                           "ORDER BY user_id FOR UPDATE NOWAIT";
            PreparedStatement lockStmt = conn.prepareStatement(lockSql);
            lockStmt.setLong(1, firstLock);
            lockStmt.setLong(2, secondLock);

            ResultSet rs;
            try {
                rs = lockStmt.executeQuery();
            } catch (SQLException e) {
                // NOWAIT throws exception if rows are locked - fail fast
                conn.rollback();
                logger.warning(String.format("Transfer blocked by concurrent operation: %s -> %s", 
                    fromUserId, toUserId));
                return new TransferResult(false, null, "Account temporarily locked, retry", null);
            }

            BigDecimal fromBalance = null;
            BigDecimal toBalance = null;

            while (rs.next()) {
                long userId = rs.getLong("user_id");
                BigDecimal balance = rs.getBigDecimal("balance");
                if (userId == fromUserId) fromBalance = balance;
                else if (userId == toUserId) toBalance = balance;
            }

            if (fromBalance == null || toBalance == null) {
                conn.rollback();
                return new TransferResult(false, null, "Account not found", null);
            }

            // DEFENSE 5: Balance check with locked rows
            if (fromBalance.compareTo(amount) < 0) {
                conn.rollback();
                return new TransferResult(false, null, "Insufficient funds", null);
            }

            // DEFENSE 6: Atomic double-entry bookkeeping
            // Create pending transfer record first (Two-Phase pattern)
            String insertTransferSql = 
                "INSERT INTO transfers (id, from_user, to_user, amount, status, description, created_at) " +
                "VALUES (?, ?, ?, ?, 'PENDING', ?, NOW())";
            PreparedStatement insertStmt = conn.prepareStatement(insertTransferSql);
            insertStmt.setString(1, transferId);
            insertStmt.setLong(2, fromUserId);
            insertStmt.setLong(3, toUserId);
            insertStmt.setBigDecimal(4, amount);
            insertStmt.setString(5, description);
            insertStmt.executeUpdate();

            // Debit source account
            String debitSql = "UPDATE wallets SET balance = balance - ?, updated_at = NOW() " +
                            "WHERE user_id = ?";
            PreparedStatement debitStmt = conn.prepareStatement(debitSql);
            debitStmt.setBigDecimal(1, amount);
            debitStmt.setLong(2, fromUserId);
            int debitRows = debitStmt.executeUpdate();

            // Credit destination account
            String creditSql = "UPDATE wallets SET balance = balance + ?, updated_at = NOW() " +
                             "WHERE user_id = ?";
            PreparedStatement creditStmt = conn.prepareStatement(creditSql);
            creditStmt.setBigDecimal(1, amount);
            creditStmt.setLong(2, toUserId);
            int creditRows = creditStmt.executeUpdate();

            // DEFENSE 7: Verify both operations succeeded
            if (debitRows != 1 || creditRows != 1) {
                conn.rollback();
                logger.severe(String.format("Transfer integrity failure: debit=%d, credit=%d", 
                    debitRows, creditRows));
                return new TransferResult(false, null, "Transfer failed - integrity check", null);
            }

            // Mark transfer as completed
            String completeSql = "UPDATE transfers SET status = 'COMPLETED', completed_at = NOW() " +
                               "WHERE id = ?";
            PreparedStatement completeStmt = conn.prepareStatement(completeSql);
            completeStmt.setString(1, transferId);
            completeStmt.executeUpdate();

            // DEFENSE 8: Audit trail
            recordAuditLog(conn, transferId, fromUserId, toUserId, amount, "TRANSFER_COMPLETED");

            conn.commit();

            TransferResult result = new TransferResult(true, transferId, null, 
                fromBalance.subtract(amount));

            // Store for idempotency
            completedTransfers.put(idempotencyKey, result);

            logger.info(String.format("Transfer completed: id=%s, from=%d, to=%d, amount=%s",
                transferId, fromUserId, toUserId, amount));

            // DEFENSE 9: Emit event for monitoring/alerting
            emitTransferEvent(transferId, fromUserId, toUserId, amount);

            return result;

        } catch (SQLException e) {
            if (conn != null) {
                try {
                    conn.rollback();
                    // Mark transfer as failed if record exists
                    markTransferFailed(conn, transferId, e.getMessage());
                } catch (SQLException ex) {
                    logger.severe("Rollback failed: " + ex.getMessage());
                }
            }
            logger.severe(String.format("Transfer failed: %s -> %s, error=%s", 
                fromUserId, toUserId, e.getMessage()));
            return new TransferResult(false, null, "Transfer failed", null);
        } finally {
            lock2.unlock();
            lock1.unlock();
            if (conn != null) {
                try { conn.close(); } catch (SQLException e) { /* log */ }
            }
        }
    }

    private void recordAuditLog(Connection conn, String transferId, long fromUser, 
                                long toUser, BigDecimal amount, String event) throws SQLException {
        String sql = "INSERT INTO audit_log (transfer_id, from_user, to_user, amount, event, " +
                   "timestamp, ip_address, user_agent) VALUES (?, ?, ?, ?, ?, NOW(), ?, ?)";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, transferId);
        stmt.setLong(2, fromUser);
        stmt.setLong(3, toUser);
        stmt.setBigDecimal(4, amount);
        stmt.setString(5, event);
        stmt.setString(6, "internal"); // Would come from request context
        stmt.setString(7, "internal");
        stmt.executeUpdate();
    }

    private void markTransferFailed(Connection conn, String transferId, String error) {
        try {
            String sql = "UPDATE transfers SET status = 'FAILED', error = ?, completed_at = NOW() " +
                       "WHERE id = ? AND status = 'PENDING'";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, error.substring(0, Math.min(error.length(), 500)));
            stmt.setString(2, transferId);
            stmt.executeUpdate();
            conn.commit();
        } catch (SQLException e) {
            logger.severe("Failed to mark transfer as failed: " + e.getMessage());
        }
    }

