var db *sql.DB

type TransferRequest struct {
	FromAccount string  `json:"from_account"`
	ToAccount   string  `json:"to_account"`
	Amount      float64 `json:"amount"`
}

var ErrInsufficientFunds = errors.New("insufficient funds")

// SECURE: Atomic transaction with row-level locking
func transferFundsSecure(w http.ResponseWriter, r *http.Request) {
	var req TransferRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate input
	if req.Amount <= 0 {
		http.Error(w, "Invalid amount", http.StatusBadRequest)
		return
	}

	ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
	defer cancel()

	err := executeAtomicTransfer(ctx, req)
	if errors.Is(err, ErrInsufficientFunds) {
		http.Error(w, "Insufficient funds", http.StatusBadRequest)
		return
	}
	if err != nil {
		log.Printf("Transfer error: %v", err)
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}

func executeAtomicTransfer(ctx context.Context, req TransferRequest) error {
	// Begin transaction with SERIALIZABLE isolation
	tx, err := db.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelSerializable})
	if err != nil {
		return err
	}
	defer tx.Rollback() // Rollback if not committed

	// SECURE: SELECT FOR UPDATE locks the row, preventing concurrent reads
	var balance float64
	err = tx.QueryRowContext(ctx,
		"SELECT balance FROM accounts WHERE id = $1 FOR UPDATE",
		req.FromAccount).Scan(&balance)
	if err != nil {
		return err
	}

	// Check with locked row - no race condition possible
	if balance < req.Amount {
		return ErrInsufficientFunds
	}

	// Atomic deduction
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance - $1 WHERE id = $2",
		req.Amount, req.FromAccount)
	if err != nil {
		return err
	}

	// Atomic addition
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance + $1 WHERE id = $2",
		req.Amount, req.ToAccount)
	if err != nil {
		return err
	}

	// Commit transaction atomically
	return tx.Commit()
}
```

**Key Security Controls**:
- **SELECT FOR UPDATE**: Acquires exclusive row lock preventing concurrent reads until transaction completes
- **SERIALIZABLE isolation**: Highest isolation level prevents phantom reads and write skew anomalies
- **Atomic transaction**: All operations succeed or fail together, no partial state
- **Context timeout**: Prevents deadlocks from holding locks indefinitely

For high-throughput systems, pessimistic locking (SELECT FOR UPDATE) can create bottlenecks. You can use optimistic concurrency control, distributed locks, or idempotency patterns. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/google/uuid"
	_ "github.com/lib/pq"
	"golang.org/x/time/rate"
)

var (
	db          *sql.DB
	redisClient *redis.Client
	rateLimiter = make(map[string]*rate.Limiter)
	rateMu      sync.RWMutex
)

type TransferRequest struct {
	FromAccount   string  `json:"from_account"`
	ToAccount     string  `json:"to_account"`
	Amount        float64 `json:"amount"`
	IdempotencyKey string `json:"idempotency_key"`
}

type AuditLog struct {
	TransactionID  string    `json:"transaction_id"`
	FromAccount    string    `json:"from_account"`
	ToAccount      string    `json:"to_account"`
	Amount         float64   `json:"amount"`
	Status         string    `json:"status"`
	Timestamp      time.Time `json:"timestamp"`
	ClientIP       string    `json:"client_ip"`
	IdempotencyKey string    `json:"idempotency_key"`
}

var (
	ErrInsufficientFunds = errors.New("insufficient funds")
	ErrVersionConflict   = errors.New("version conflict - retry")
	ErrDuplicateRequest  = errors.New("duplicate request")
	ErrRateLimited       = errors.New("rate limited")
)

// Production handler with defense in depth
func transferFundsProduction(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()

	var req TransferRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	clientIP := r.RemoteAddr
	transactionID := uuid.New().String()

	// Layer 1: Rate limiting per account
	if !checkRateLimit(req.FromAccount) {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			Status:        "RATE_LIMITED",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// Layer 2: Idempotency check with distributed lock
	if req.IdempotencyKey != "" {
		duplicate, err := checkIdempotency(ctx, req.IdempotencyKey)
		if err != nil {
			log.Printf("Idempotency check error: %v", err)
		}
		if duplicate {
			http.Error(w, "Duplicate request", http.StatusConflict)
			return
		}
	}

	// Layer 3: Distributed lock to prevent concurrent processing
	lockKey := fmt.Sprintf("transfer_lock:%s", req.FromAccount)
	locked, err := acquireDistributedLock(ctx, lockKey, 10*time.Second)
	if err != nil || !locked {
		http.Error(w, "Service temporarily unavailable", http.StatusServiceUnavailable)
		return
	}
	defer releaseDistributedLock(ctx, lockKey)

	// Layer 4: Optimistic concurrency control with retry
	var lastErr error
	for attempt := 0; attempt < 3; attempt++ {
		lastErr = executeOptimisticTransfer(ctx, req, transactionID)
		if lastErr == nil {
			break
		}
		if !errors.Is(lastErr, ErrVersionConflict) {
			break
		}
		time.Sleep(time.Duration(attempt*100) * time.Millisecond)
	}

	if errors.Is(lastErr, ErrInsufficientFunds) {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			ToAccount:     req.ToAccount,
			Amount:        req.Amount,
			Status:        "INSUFFICIENT_FUNDS",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		http.Error(w, "Insufficient funds", http.StatusBadRequest)
		return
	}
	if lastErr != nil {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			Status:        "FAILED",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		log.Printf("Transfer failed: %v", lastErr)
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	// Mark idempotency key as used
	if req.IdempotencyKey != "" {
		markIdempotencyUsed(ctx, req.IdempotencyKey, transactionID)
	}

	logAudit(ctx, AuditLog{
		TransactionID:  transactionID,
		FromAccount:    req.FromAccount,
		ToAccount:      req.ToAccount,
		Amount:         req.Amount,
		Status:         "SUCCESS",
		Timestamp:      time.Now(),
		ClientIP:       clientIP,
		IdempotencyKey: req.IdempotencyKey,
	})

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"status":         "success",
		"transaction_id": transactionID,
	})
}

// Optimistic Concurrency Control using version column
func executeOptimisticTransfer(ctx context.Context, req TransferRequest, txID string) error {
	tx, err := db.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelReadCommitted})
	if err != nil {
		return err
	}
	defer tx.Rollback()

	// Read current state with version
	var balance float64
	var version int64
	err = tx.QueryRowContext(ctx,
		"SELECT balance, version FROM accounts WHERE id = $1",
		req.FromAccount).Scan(&balance, &version)
	if err != nil {
		return err
	}

	if balance < req.Amount {
		return ErrInsufficientFunds
	}

	// Conditional update - only succeeds if version unchanged
	result, err := tx.ExecContext(ctx,
		`UPDATE accounts 
		 SET balance = balance - $1, version = version + 1, updated_at = NOW()
		 WHERE id = $2 AND version = $3 AND balance >= $1`,
		req.Amount, req.FromAccount, version)
	if err != nil {
		return err
	}

	rowsAffected, _ := result.RowsAffected()
	if rowsAffected == 0 {
		// Version changed or balance insufficient - concurrent modification detected
		return ErrVersionConflict
	}

	// Credit destination
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance + $1, version = version + 1 WHERE id = $2",
		req.Amount, req.ToAccount)
	if err != nil {
		return err
	}

	// Record transaction for audit trail
	_, err = tx.ExecContext(ctx,
		`INSERT INTO transactions (id, from_account, to_account, amount, status, created_at)
		 VALUES ($1, $2, $3, $4, 'COMPLETED', NOW())`,
		txID, req.FromAccount, req.ToAccount, req.Amount)
	if err != nil {
		return err
	}

	return tx.Commit()
}

// Rate limiting per account
func checkRateLimit(accountID string) bool {
	rateMu.Lock()
	defer rateMu.Unlock()

	limiter, exists := rateLimiter[accountID]
	if !exists {
		// 10 requests per second with burst of 20
		limiter = rate.NewLimiter(10, 20)
		rateLimiter[accountID] = limiter
	}
	return limiter.Allow()
}

// Distributed lock using Redis
func acquireDistributedLock(ctx context.Context, key string, ttl time.Duration) (bool, error) {
	lockValue := uuid.New().String()
	result, err := redisClient.SetNX(ctx, key, lockValue, ttl).Result()
	return result, err
}

func releaseDistributedLock(ctx context.Context, key string) {
	redisClient.Del(ctx, key)
}

// Idempotency tracking
func checkIdempotency(ctx context.Context, key string) (bool, error) {
	hash := sha256.Sum256([]byte(key))
	hashKey := "idempotency:" + hex.EncodeToString(hash[:])
	exists, err := redisClient.Exists(ctx, hashKey).Result()
	return exists > 0, err
}

func markIdempotencyUsed(ctx context.Context, key, txID string) {
	hash := sha256.Sum256([]byte(key))
	hashKey := "idempotency:" + hex.EncodeToString(hash[:])
	// Store for 24 hours
	redisClient.Set(ctx, hashKey, txID, 24*time.Hour)
}

// Audit logging
func logAudit(ctx context.Context, audit AuditLog) {
	data, _ := json.Marshal(audit)
	log.Printf("AUDIT: %s", string(data))
	// In production: send to SIEM, write to audit table, etc.
}
