const redis = new Redis(process.env.REDIS_URL);

// Rate limiter: 10 transfers per minute per user
const rateLimiter = new RateLimiterRedis({
  storeClient: redis,
  keyPrefix: 'transfer_limit',
  points: 10,
  duration: 60,
});

// Distributed lock with automatic expiry
class DistributedLock {
  constructor(redis, lockTimeout = 10000) {
    this.redis = redis;
    this.lockTimeout = lockTimeout;
  }

  async acquire(key) {
    const token = crypto.randomBytes(16).toString('hex');
    const lockKey = `lock:${key}`;

    // SET NX with expiry - atomic lock acquisition
    const acquired = await this.redis.set(
      lockKey,
      token,
      'PX',
      this.lockTimeout,
      'NX'
    );

    return acquired ? token : null;
  }

  async release(key, token) {
    // Lua script for atomic check-and-delete
    const script = `
      if redis.call("get", KEYS[1]) == ARGV[1] then
        return redis.call("del", KEYS[1])
      else
        return 0
      end
    `;
    return await this.redis.eval(script, 1, `lock:${key}`, token);
  }
}

const lock = new DistributedLock(redis);

// Idempotency key storage (24-hour TTL)
async function checkIdempotency(idempotencyKey) {
  const existing = await redis.get(`idempotency:${idempotencyKey}`);
  return existing ? JSON.parse(existing) : null;
}

async function storeIdempotency(idempotencyKey, result) {
  await redis.setex(
    `idempotency:${idempotencyKey}`,
    86400, // 24 hours
    JSON.stringify(result)
  );
}

