  if (cachedResult) {
    console.log(`Returning cached result for idempotency key: ${idempotencyKey}`);
    return res.status(cachedResult.status).json(cachedResult.body);
  }

  // 4. DISTRIBUTED LOCK - Prevent concurrent transfers from same user
  const lockToken = await lock.acquire(`transfer:${fromUser}`);
  if (!lockToken) {
    return res.status(409).json({
      error: 'Another transfer in progress',
      retryAfter: 1
    });
  }

  const client = await pool.connect();

  try {
    // 5. OPTIMISTIC CONCURRENCY with version check
    await client.query('BEGIN');

    // Get current balance WITH version number
    const walletResult = await client.query(
      'SELECT balance, version FROM wallets WHERE user_id = $1',
      [fromUser]
    );

    if (walletResult.rows.length === 0) {
      await client.query('ROLLBACK');
      const result = { status: 404, body: { error: 'User not found' } };
      await storeIdempotency(idempotencyKey, result);
      return res.status(404).json(result.body);
    }

    const { balance, version } = walletResult.rows[0];

    if (balance < amount) {
      await client.query('ROLLBACK');
      const result = { status: 400, body: { error: 'Insufficient funds' } };
      await storeIdempotency(idempotencyKey, result);
      return res.status(400).json(result.body);
    }

    // 6. OPTIMISTIC UPDATE - Fails if version changed
    const updateResult = await client.query(
      `UPDATE wallets 
       SET balance = balance - $1, version = version + 1, updated_at = NOW()
       WHERE user_id = $2 AND version = $3
       RETURNING balance`,
      [amount, fromUser, version]
    );

    if (updateResult.rowCount === 0) {
      await client.query('ROLLBACK');
      return res.status(409).json({
        error: 'Concurrent modification detected',
        retryAfter: 0.1
      });
    }

    // Credit recipient
    await client.query(
      'UPDATE wallets SET balance = balance + $1, version = version + 1 WHERE user_id = $2',
      [amount, toUser]
    );

    // 7. AUDIT LOG with correlation ID
    const transactionId = crypto.randomUUID();
    await client.query(
      `INSERT INTO transactions 
       (id, from_user, to_user, amount, idempotency_key, status, created_at)
       VALUES ($1, $2, $3, $4, $5, 'completed', NOW())`,
      [transactionId, fromUser, toUser, amount, idempotencyKey]
    );

    await client.query('COMMIT');

    const result = {
      status: 200,
      body: {
        success: true,
        transactionId,
        newBalance: updateResult.rows[0].balance
      }
    };

    // Cache successful result for idempotency
    await storeIdempotency(idempotencyKey, result);

    // 8. METRICS & MONITORING
    console.log(JSON.stringify({
      event: 'transfer_completed',
      transactionId,
      fromUser,
      toUser,
      amount,
      timestamp: new Date().toISOString()
    }));

    res.json(result.body);

  } catch (error) {
    await client.query('ROLLBACK');

    console.error(JSON.stringify({
      event: 'transfer_failed',
      error: error.message,
      fromUser,
      idempotencyKey,
      timestamp: new Date().toISOString()
    }));

    res.status(500).json({ error: 'Transfer failed' });
  } finally {
    client.release();
    await lock.release(`transfer:${fromUser}`, lockToken);
  }
});

app.listen(3000);
```

