            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            try {
                // SECURE: Atomic check-and-update with row locking
                // SELECT FOR UPDATE acquires exclusive lock on the row
                String lockSql = "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE";
                PreparedStatement lockStmt = conn.prepareStatement(lockSql);
                lockStmt.setLong(1, fromAccount);
                ResultSet rs = lockStmt.executeQuery();

                if (rs.next()) {
                    BigDecimal currentBalance = rs.getBigDecimal("balance");

                    // Check with locked row - no race condition possible
                    if (currentBalance.compareTo(amount) >= 0) {
                        // Atomic update within same transaction
                        String deductSql = "UPDATE accounts SET balance = balance - ? WHERE account_id = ? AND balance >= ?";
                        PreparedStatement deductStmt = conn.prepareStatement(deductSql);
                        deductStmt.setBigDecimal(1, amount);
                        deductStmt.setLong(2, fromAccount);
                        deductStmt.setBigDecimal(3, amount);
                        int rowsUpdated = deductStmt.executeUpdate();

                        if (rowsUpdated == 1) {
                            String addSql = "UPDATE accounts SET balance = balance + ? WHERE account_id = ?";
                            PreparedStatement addStmt = conn.prepareStatement(addSql);
                            addStmt.setBigDecimal(1, amount);
                            addStmt.setLong(2, toAccount);
                            addStmt.executeUpdate();

                            conn.commit();
                            logger.info("Transfer successful: " + fromAccount + " -> " + toAccount + ": $" + amount);
                            return true;
                        }
                    }
                }
                conn.rollback();
                return false;

            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            logger.severe("Transfer failed: " + e.getMessage());
            return false;
        }
    }
}
