**Key Security Controls**:
- `SELECT FOR UPDATE` acquires exclusive row lock, preventing concurrent reads until transaction completes
- `TRANSACTION_SERIALIZABLE` ensures highest isolation level
- WHERE clause includes `balance >= ?` as defense in depth - second check at update time
- Single transaction wraps all operations - atomic success or rollback

Excellent question! Row-level locking can create bottlenecks in high-throughput systems. For production environments, you need optimistic concurrency control with version checks, distributed locks for multi-node deployments, and idempotency keys to prevent duplicate processing.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.math.BigDecimal;
import java.util.UUID;
import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;
import redis.clients.jedis.Jedis;
import redis.clients.jedis.params.SetParams;

public class DistributedTransferService {
    private static final Logger logger = Logger.getLogger(DistributedTransferService.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/bank";
    private static final String DB_USER = "bankapp";
    private static final String DB_PASS = "password";
    private static final int LOCK_TIMEOUT_SECONDS = 30;
    private static final int MAX_RETRIES = 3;

    private final Jedis redisClient;
    private final TransferMetrics metrics;

    public DistributedTransferService(Jedis redisClient, TransferMetrics metrics) {
        this.redisClient = redisClient;
        this.metrics = metrics;
    }

    public TransferResult transferFunds(
            String idempotencyKey,
            long fromAccount, 
            long toAccount, 
            BigDecimal amount,
            String requesterId) {

        // Input validation
        if (amount.compareTo(BigDecimal.ZERO) <= 0 || amount.compareTo(new BigDecimal("1000000")) > 0) {
            return TransferResult.failure("INVALID_AMOUNT", "Amount must be between 0 and 1,000,000");
        }

        // DEFENSE 1: Idempotency check - prevent duplicate processing
        String idempotencyResult = checkIdempotency(idempotencyKey);
        if (idempotencyResult != null) {
            logger.info("Duplicate request detected: " + idempotencyKey);
            return TransferResult.duplicate(idempotencyResult);
        }

        // DEFENSE 2: Distributed lock to prevent race conditions across nodes
        String lockKey = "transfer_lock:" + fromAccount;
        String lockValue = UUID.randomUUID().toString();

        if (!acquireDistributedLock(lockKey, lockValue)) {
            metrics.incrementLockContention();
            return TransferResult.failure("LOCK_CONTENTION", "Account is busy, please retry");
        }

        try {
            return executeTransferWithOptimisticLocking(
                idempotencyKey, fromAccount, toAccount, amount, requesterId);
        } finally {
            releaseDistributedLock(lockKey, lockValue);
        }
    }

    private TransferResult executeTransferWithOptimisticLocking(
            String idempotencyKey,
            long fromAccount,
            long toAccount,
            BigDecimal amount,
            String requesterId) {

        int retries = 0;
        while (retries < MAX_RETRIES) {
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                conn.setAutoCommit(false);

                try {
                    // DEFENSE 3: Optimistic locking with version check
                    String selectSql = 
                        "SELECT balance, version FROM accounts WHERE account_id = ?";
                    PreparedStatement selectStmt = conn.prepareStatement(selectSql);
                    selectStmt.setLong(1, fromAccount);
                    ResultSet rs = selectStmt.executeQuery();

                    if (!rs.next()) {
                        conn.rollback();
                        return TransferResult.failure("ACCOUNT_NOT_FOUND", "Source account not found");
                    }

                    BigDecimal currentBalance = rs.getBigDecimal("balance");
                    long currentVersion = rs.getLong("version");

                    if (currentBalance.compareTo(amount) < 0) {
                        conn.rollback();
                        return TransferResult.failure("INSUFFICIENT_FUNDS", "Insufficient balance");
                    }

                    // DEFENSE 4: Atomic update with version check (optimistic lock)
                    String updateSql = 
                        "UPDATE accounts SET balance = balance - ?, version = version + 1, updated_at = NOW() " +
                        "WHERE account_id = ? AND version = ? AND balance >= ?";
                    PreparedStatement updateStmt = conn.prepareStatement(updateSql);
                    updateStmt.setBigDecimal(1, amount);
                    updateStmt.setLong(2, fromAccount);
                    updateStmt.setLong(3, currentVersion);
                    updateStmt.setBigDecimal(4, amount);

                    int rowsUpdated = updateStmt.executeUpdate();

                    if (rowsUpdated == 0) {
                        // Version changed - concurrent modification detected, retry
                        conn.rollback();
                        retries++;
                        metrics.incrementOptimisticLockRetry();
                        logger.info("Optimistic lock conflict, retry " + retries);
                        continue;
                    }

                    // Credit destination account
                    String creditSql = 
                        "UPDATE accounts SET balance = balance + ?, version = version + 1, updated_at = NOW() " +
                        "WHERE account_id = ?";
                    PreparedStatement creditStmt = conn.prepareStatement(creditSql);
                    creditStmt.setBigDecimal(1, amount);
                    creditStmt.setLong(2, toAccount);
                    creditStmt.executeUpdate();

                    // DEFENSE 5: Record transaction for audit and idempotency
                    String txId = recordTransaction(
                        conn, idempotencyKey, fromAccount, toAccount, amount, requesterId);

                    conn.commit();

                    // Store idempotency key with result
                    storeIdempotencyResult(idempotencyKey, txId);

                    metrics.recordSuccessfulTransfer(amount);
                    logger.info("Transfer completed: " + txId);

                    return TransferResult.success(txId);

                } catch (SQLException e) {
                    conn.rollback();
                    throw e;
                }
            } catch (SQLException e) {
                logger.severe("Database error: " + e.getMessage());
                metrics.incrementDatabaseError();
            }
            retries++;
        }

        return TransferResult.failure("MAX_RETRIES_EXCEEDED", "Transaction failed after retries");
    }

    private boolean acquireDistributedLock(String lockKey, String lockValue) {
        // Redis SET with NX (only if not exists) and EX (expiration)
        SetParams params = SetParams.setParams().nx().ex(LOCK_TIMEOUT_SECONDS);
        String result = redisClient.set(lockKey, lockValue, params);
        return "OK".equals(result);
    }

    private void releaseDistributedLock(String lockKey, String lockValue) {
        // Only release if we own the lock (Lua script for atomicity)
        String luaScript = 
            "if redis.call('get', KEYS[1]) == ARGV[1] then " +
            "    return redis.call('del', KEYS[1]) " +
            "else " +
            "    return 0 " +
            "end";
        redisClient.eval(luaScript, 1, lockKey, lockValue);
    }

    private String checkIdempotency(String idempotencyKey) {
        return redisClient.get("idempotency:" + idempotencyKey);
    }

    private void storeIdempotencyResult(String idempotencyKey, String result) {
        // Store for 24 hours
        redisClient.setex("idempotency:" + idempotencyKey, 86400, result);
    }

    private String recordTransaction(
            Connection conn, 
            String idempotencyKey,
            long fromAccount, 
            long toAccount, 
            BigDecimal amount,
            String requesterId) throws SQLException {

        String txId = UUID.randomUUID().toString();
        String insertSql = 
            "INSERT INTO transactions (tx_id, idempotency_key, from_account, to_account, amount, requester_id, created_at) " +
            "VALUES (?, ?, ?, ?, ?, ?, NOW())";
        PreparedStatement insertStmt = conn.prepareStatement(insertSql);
        insertStmt.setString(1, txId);
        insertStmt.setString(2, idempotencyKey);
        insertStmt.setLong(3, fromAccount);
        insertStmt.setLong(4, toAccount);
        insertStmt.setBigDecimal(5, amount);
        insertStmt.setString(6, requesterId);
        insertStmt.executeUpdate();

        return txId;
    }
}

// Supporting classes
class TransferResult {
    private final boolean success;
    private final String transactionId;
    private final String errorCode;
    private final String errorMessage;
    private final boolean duplicate;

    private TransferResult(boolean success, String transactionId, String errorCode, String errorMessage, boolean duplicate) {
        this.success = success;
        this.transactionId = transactionId;
        this.errorCode = errorCode;
        this.errorMessage = errorMessage;
        this.duplicate = duplicate;
    }

    public static TransferResult success(String transactionId) {
        return new TransferResult(true, transactionId, null, null, false);
    }

    public static TransferResult failure(String errorCode, String errorMessage) {
        return new TransferResult(false, null, errorCode, errorMessage, false);
    }

    public static TransferResult duplicate(String previousResult) {
        return new TransferResult(true, previousResult, null, null, true);
    }

    public boolean isSuccess() { return success; }
    public String getTransactionId() { return transactionId; }
    public String getErrorCode() { return errorCode; }
    public boolean isDuplicate() { return duplicate; }
}

interface TransferMetrics {
    void incrementLockContention();
    void incrementOptimisticLockRetry();
    void incrementDatabaseError();
    void recordSuccessfulTransfer(BigDecimal amount);
}
