```go
package main

import (
	"context"
	"database/sql"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

var db *sql.DB

type SecureWalletService struct {
	db *sql.DB
}

// SECURE: Atomic transfer using database transaction with row locking
func (w *SecureWalletService) Transfer(ctx context.Context, fromUserID, toUserID int, amount float64) error {
	// Input validation
	if amount <= 0 {
		return fmt.Errorf("invalid amount")
	}
	if fromUserID == toUserID {
		return fmt.Errorf("cannot transfer to self")
	}

	// Start transaction with serializable isolation
	tx, err := w.db.BeginTx(ctx, &sql.TxOptions{
		Isolation: sql.LevelSerializable,
	})
	if err != nil {
		return fmt.Errorf("failed to start transaction: %w", err)
	}
	defer tx.Rollback() // Will be no-op if committed

	// SECURE: SELECT FOR UPDATE locks the row, preventing concurrent modifications
	var balance float64
	err = tx.QueryRowContext(ctx,
		"SELECT balance FROM wallets WHERE user_id = $1 FOR UPDATE",
		fromUserID,
	).Scan(&balance)
	if err != nil {
		return fmt.Errorf("failed to get balance: %w", err)
	}

	// Check with locked row - no race possible now
	if balance < amount {
		return fmt.Errorf("insufficient funds")
	}

	// Deduct from sender (row is still locked)
	result, err := tx.ExecContext(ctx,
		"UPDATE wallets SET balance = balance - $1, updated_at = NOW() WHERE user_id = $2 AND balance >= $1",
		amount, fromUserID,
	)
	if err != nil {
		return fmt.Errorf("failed to deduct: %w", err)
	}

	// Verify the update affected exactly one row
	rowsAffected, _ := result.RowsAffected()
	if rowsAffected != 1 {
		return fmt.Errorf("transfer failed: balance changed")
	}

	// Add to receiver
	_, err = tx.ExecContext(ctx,
		"UPDATE wallets SET balance = balance + $1, updated_at = NOW() WHERE user_id = $2",
		amount, toUserID,
	)
	if err != nil {
		return fmt.Errorf("failed to credit: %w", err)
	}

	// Commit transaction atomically
	if err := tx.Commit(); err != nil {
		return fmt.Errorf("failed to commit: %w", err)
	}

	log.Printf("Transfer completed: %d -> %d, amount: %.2f", fromUserID, toUserID, amount)
	return nil
}
```

**Key Security Controls**:
- **SELECT FOR UPDATE**: Acquires an exclusive row lock, preventing other transactions from reading or modifying the row until the lock is released
- **Serializable Isolation**: Ensures transactions execute as if they were sequential, preventing phantom reads and race conditions
- **Double-check in UPDATE**: The `WHERE balance >= $1` clause provides defense-in-depth, ensuring the deduction only succeeds if sufficient funds exist
- **RowsAffected verification**: Confirms exactly one row was updated, detecting any concurrent interference

