	return s.sessions[token] // Unsafe read
}

func (s *UnsafeSessionStore) Set(token string, session *Session) {
	s.sessions[token] = session // Unsafe write - can corrupt map
}

// =============================================================================
// SECURE: Production-grade session store with proper synchronization
// =============================================================================

type SecureSessionStore struct {
	mu           sync.RWMutex
	sessions     map[string]*Session
	metrics      *SessionMetrics
	cleanupDone  chan struct{}
	shutdownOnce sync.Once
}

type SessionMetrics struct {
	ActiveCount   int64
	TotalCreated  int64
	TotalExpired  int64
	ConcurrentOps int64
}

func NewSecureSessionStore() *SecureSessionStore {
	store := &SecureSessionStore{
		sessions:    make(map[string]*Session),
		metrics:     &SessionMetrics{},
		cleanupDone: make(chan struct{}),
	}

	// Background cleanup goroutine
	go store.cleanupExpiredSessions()

	return store
}

// SECURE: Read with RLock allows concurrent readers
func (s *SecureSessionStore) Get(ctx context.Context, token string) (*Session, error) {
	atomic.AddInt64(&s.metrics.ConcurrentOps, 1)
	defer atomic.AddInt64(&s.metrics.ConcurrentOps, -1)

	// Check context for cancellation
	select {
	case <-ctx.Done():
		return nil, ctx.Err()
	default:
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	session, exists := s.sessions[token]
	if !exists {
		return nil, fmt.Errorf("session not found")
	}

	// Check expiration while holding lock
	if time.Now().After(session.ExpiresAt) {
		return nil, fmt.Errorf("session expired")
	}

	// Return a copy to prevent external mutation
	return &Session{
		UserID:    session.UserID,
		Token:     session.Token,
		ExpiresAt: session.ExpiresAt,
		Role:      session.Role,
	}, nil
}

// SECURE: Write with exclusive Lock
func (s *SecureSessionStore) Set(ctx context.Context, token string, session *Session) error {
	atomic.AddInt64(&s.metrics.ConcurrentOps, 1)
	defer atomic.AddInt64(&s.metrics.ConcurrentOps, -1)

	select {
	case <-ctx.Done():
		return ctx.Err()
	default:
	}

	// Validate session before storing
	if session == nil || token == "" {
		return fmt.Errorf("invalid session or token")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Store a copy to prevent external mutation
	s.sessions[token] = &Session{
		UserID:    session.UserID,
		Token:     session.Token,
		ExpiresAt: session.ExpiresAt,
		Role:      session.Role,
	}

	atomic.AddInt64(&s.metrics.TotalCreated, 1)
	atomic.AddInt64(&s.metrics.ActiveCount, 1)

	log.Printf("[AUDIT] Session created: user=%d, expires=%s", session.UserID, session.ExpiresAt)
	return nil
}

// SECURE: Atomic check-and-delete operation
func (s *SecureSessionStore) Delete(ctx context.Context, token string) error {
	select {
	case <-ctx.Done():
		return ctx.Err()
	default:
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if session, exists := s.sessions[token]; exists {
		delete(s.sessions, token)
		atomic.AddInt64(&s.metrics.ActiveCount, -1)
		log.Printf("[AUDIT] Session deleted: user=%d", session.UserID)
	}

	return nil
}

// SECURE: Atomic compare-and-swap for role elevation (prevents TOCTOU)
func (s *SecureSessionStore) ElevateRole(ctx context.Context, token string, newRole string, requiredCurrentRole string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	session, exists := s.sessions[token]
	if !exists {
		return fmt.Errorf("session not found")
	}

	// Atomic check-and-modify - no race window
	if session.Role != requiredCurrentRole {
		log.Printf("[SECURITY] Role elevation denied: expected=%s, actual=%s, user=%d",
			requiredCurrentRole, session.Role, session.UserID)
		return fmt.Errorf("role mismatch")
	}

	session.Role = newRole
	log.Printf("[AUDIT] Role elevated: user=%d, from=%s, to=%s",
		session.UserID, requiredCurrentRole, newRole)

	return nil
}

// Background cleanup of expired sessions
func (s *SecureSessionStore) cleanupExpiredSessions() {
	ticker := time.NewTicker(1 * time.Minute)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			s.mu.Lock()
			now := time.Now()
			expiredCount := int64(0)

			for token, session := range s.sessions {
				if now.After(session.ExpiresAt) {
					delete(s.sessions, token)
					expiredCount++
				}
			}

			s.mu.Unlock()

			if expiredCount > 0 {
				atomic.AddInt64(&s.metrics.TotalExpired, expiredCount)
				atomic.AddInt64(&s.metrics.ActiveCount, -expiredCount)
				log.Printf("[CLEANUP] Removed %d expired sessions", expiredCount)
			}

		case <-s.cleanupDone:
			return
		}
	}
}

// Graceful shutdown
func (s *SecureSessionStore) Shutdown() {
	s.shutdownOnce.Do(func() {
		close(s.cleanupDone)
		log.Printf("[INFO] Session store shutdown complete")
	})
}

// GetMetrics returns current metrics (thread-safe via atomics)
func (s *SecureSessionStore) GetMetrics() SessionMetrics {
	return SessionMetrics{
		ActiveCount:   atomic.LoadInt64(&s.metrics.ActiveCount),
		TotalCreated:  atomic.LoadInt64(&s.metrics.TotalCreated),
		TotalExpired:  atomic.LoadInt64(&s.metrics.TotalExpired),
		ConcurrentOps: atomic.LoadInt64(&s.metrics.ConcurrentOps),
	}
}

// =============================================================================
// Alternative: sync.Map for simple key-value with high read concurrency
// =============================================================================

type SyncMapSessionStore struct {
	sessions sync.Map // Built-in concurrent map
}

func (s *SyncMapSessionStore) Get(token string) (*Session, bool) {
	val, ok := s.sessions.Load(token)
	if !ok {
		return nil, false
	}
	return val.(*Session), true
}

func (s *SyncMapSessionStore) Set(token string, session *Session) {
	s.sessions.Store(token, session)
}

// CompareAndSwap for atomic updates
func (s *SyncMapSessionStore) UpdateIfExists(token string, updateFn func(*Session) *Session) bool {
	for {
		val, ok := s.sessions.Load(token)
		if !ok {
			return false
		}
		oldSession := val.(*Session)
		newSession := updateFn(oldSession)
		if s.sessions.CompareAndSwap(token, oldSession, newSession) {
			return true
		}
		// Retry if concurrent modification detected
	}
}
