**Why This Is Dangerous**:
- Time-of-check to time-of-use (TOCTOU) vulnerability exists between SELECT and UPDATE
- Multiple concurrent requests all see the original balance before any deduction occurs
- No database-level locking prevents concurrent modifications
- Attackers can drain accounts by sending rapid parallel requests

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

// SECURE: Atomic withdrawal with row-level locking
app.post('/api/withdraw', async (req, res) => {
  const { userId, amount } = req.body;
  const client = await pool.connect();

  try {
    // Start transaction with SERIALIZABLE isolation
    await client.query('BEGIN ISOLATION LEVEL SERIALIZABLE');

    // Atomic check-and-update with row lock (SELECT FOR UPDATE)
    const result = await client.query(
      `UPDATE wallets 
       SET balance = balance - $1,
           updated_at = NOW(),
           version = version + 1
       WHERE user_id = $2 
         AND balance >= $1
       RETURNING balance, version`,
      [amount, userId]
    );

    // If no rows updated, either insufficient funds or user doesn't exist
    if (result.rowCount === 0) {
      await client.query('ROLLBACK');
      return res.status(400).json({ 
        error: 'Insufficient funds or invalid user',
        code: 'INSUFFICIENT_BALANCE'
      });
    }

    // Record transaction atomically within same transaction
    await client.query(
      `INSERT INTO transactions 
       (user_id, amount, type, wallet_version, created_at) 
       VALUES ($1, $2, $3, $4, NOW())`,
      [userId, amount, 'withdrawal', result.rows[0].version]
    );

    await client.query('COMMIT');

    res.json({ 
      success: true, 
      newBalance: result.rows[0].balance,
      transactionVersion: result.rows[0].version
    });

  } catch (error) {
    await client.query('ROLLBACK');

    // Handle serialization failures (concurrent modification detected)
    if (error.code === '40001') {
      return res.status(409).json({ 
        error: 'Transaction conflict, please retry',
        code: 'SERIALIZATION_FAILURE'
      });
    }

    console.error('Withdrawal error:', error);
    res.status(500).json({ error: 'Withdrawal failed' });
  } finally {
    client.release();
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Atomic UPDATE with condition**: Balance check and deduction happen in single SQL statement, eliminating race window
- **SERIALIZABLE isolation**: Highest isolation level detects and prevents concurrent conflicting transactions
- **Conditional UPDATE**: `WHERE balance >= $1` ensures operation only succeeds if sufficient funds exist at execution time
- **Optimistic locking**: Version column detects concurrent modifications for additional safety

