const express = require('express');
const { Pool } = require('pg');
const Redis = require('ioredis');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,
  idleTimeoutMillis: 30000
});

const redis = new Redis(process.env.REDIS_URL);

// Distributed lock manager for cross-service consistency
class DistributedLock {
  constructor(redis) {
    this.redis = redis;
    this.lockPrefix = 'wallet:lock:';
  }

  async acquire(accountIds, ttlMs = 5000) {
    // CRITICAL: Sort account IDs to prevent deadlocks
    const sortedIds = [...accountIds].sort();
    const lockId = crypto.randomUUID();
    const locks = [];

    for (const accountId of sortedIds) {
      const lockKey = `${this.lockPrefix}${accountId}`;
      const acquired = await this.redis.set(
        lockKey,
        lockId,
        'PX',
        ttlMs,
        'NX'
      );

      if (!acquired) {
        // Release any acquired locks on failure
        await this.releaseAll(locks, lockId);
        return null;
      }
      locks.push(lockKey);
    }

    return { lockId, locks, sortedIds };
  }

  async releaseAll(locks, lockId) {
    for (const lockKey of locks) {
      // Lua script ensures we only release our own lock
      await this.redis.eval(
        `if redis.call('get', KEYS[1]) == ARGV[1] then 
           return redis.call('del', KEYS[1]) 
         else 
           return 0 
         end`,
        1,
        lockKey,
        lockId
      );
    }
  }
}

const lockManager = new DistributedLock(redis);

// Rate limiter per user
const rateLimitTransfer = async (userId) => {
  const key = `ratelimit:transfer:${userId}`;
  const count = await redis.incr(key);
  if (count === 1) {
    await redis.expire(key, 60); // 60 second window
  }
  return count <= 10; // Max 10 transfers per minute
};

// Idempotency check to prevent duplicate transactions
const checkIdempotency = async (idempotencyKey) => {
  const existing = await redis.get(`idempotency:${idempotencyKey}`);
  if (existing) {
    return JSON.parse(existing);
  }
  return null;
};

const storeIdempotency = async (idempotencyKey, result, ttlSeconds = 86400) => {
  await redis.setex(
    `idempotency:${idempotencyKey}`,
    ttlSeconds,
    JSON.stringify(result)
  );
};

// PRODUCTION-SAFE: Transfer with deadlock prevention and full audit trail
app.post('/api/transfer', async (req, res) => {
  const { fromUserId, toUserId, amount, idempotencyKey } = req.body;
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

