    console.log(JSON.stringify({
      event: 'rate_limit_exceeded',
      requestId,
      userId: fromUserId
    }));
    return res.status(429).json({ 
      error: 'Transfer rate limit exceeded',
      requestId 
    });
  }

  // Acquire distributed locks in consistent order (prevents deadlocks)
  const lockResult = await lockManager.acquire([fromUserId, toUserId], 10000);

  if (!lockResult) {
    console.log(JSON.stringify({
      event: 'lock_acquisition_failed',
      requestId,
      accounts: [fromUserId, toUserId]
    }));
    return res.status(503).json({ 
